(defn- make-sample [dir offset text]
  {:name (str dir "/s" (.padStart (str offset) 2 "0") ".txt")
   :text text})

(defn- load-sample-files []
  (.concat (.map spam-samples
                 (fn [text index]
                   (make-sample "spam" index text)))
           (.map not-spam-samples
                 (fn [text index]
                   (make-sample "not_spam" index text)))))

(defn- expected-path [sample]
  (let [rel-dir (path/dirname sample.name)
        basename (path/basename sample.name ".txt")]
    (path/join st/output-dir rel-dir (str basename ".json"))))

(defn- fill-template [sample-text]
  (clojure.string/replace
   (str (Buffer.from
         ""
         "base64"))
   "__SPAM_TEXT__"
   (JSON/stringify (str (Buffer.from sample-text "base64")))))

(defn- load-input [sample]
  (JSON/parse (fill-template sample.text)))

(def- config
  {:load-input load-input
   :expected-path expected-path
   :sample-name (fn [sample] sample.name)
   :sample-subdir (fn [sample] (path/basename (path/dirname sample.name)))})

(t/before (fn [] (tu/before
                  {:TG_TOKEN {:type "plain_text" :value "~TG_TOKEN~"}
                   :TG_SECRET_TOKEN {:type "plain_text" :value "test-secret"}
                   :TG_APPROVE_CHAT {:type "plain_text" :value "-1001234567890"}})))
(t/after (fn [] (tu/after)))

(.forEach (load-sample-files) (fn [sample] (st/register-sample-test config sample)))
